import { Server as NetServer } from "http";
import { NextRequest } from "next/server";
import { Server as SocketIOServer } from "socket.io";
import { getGameServer } from "@/lib/game-server";

export const dynamic = "force-dynamic";

let io: SocketIOServer | undefined;

export async function GET(req: NextRequest) {
  // @ts-ignore
  const server = (req as any).socket?.server as NetServer;

  if (server && !io) {
    console.log("[Socket.IO] Initializing server...");

    io = new SocketIOServer(server, {
      path: "/api/socket",
      cors: {
        origin: "*",
        methods: ["GET", "POST"],
      },
    });

    // Инициализируем игровой сервер
    getGameServer(server);
  }

  return new Response("Socket.IO server ready", { status: 200 });
}